def _first_row(rows: Any, key: str, value: str) -> dict[str, Any]:
    for row in rows or []:
        if isinstance(row, dict) and row.get(key) == value:
            return row
    return {}


def _collect_values_for_key(value: Any, key: str) -> set[str]:
    values: set[str] = set()
    if isinstance(value, dict):
        for nested_key, nested_value in value.items():
            if nested_key == key and isinstance(nested_value, str):
                values.add(nested_value)
            values |= _collect_values_for_key(nested_value, key)
    elif isinstance(value, list):
        for item in value:
            values |= _collect_values_for_key(item, key)
    return values


def _dependency_preflight_observed(
    readiness: dict[str, Any],
    matrix: dict[str, Any],
    validator_plan: str,
) -> dict[str, Any]:
    contract = readiness.get("dependency_preflight_contract_v1", {})
    matrix_contract = matrix.get("dependency_preflight_negative_case_contract_v1", {})
    contract_rows = contract.get("organ_preflight_checks", [])
    matrix_rows = matrix_contract.get("preflight_negative_cases", [])
    contract_by_organ = {
        row.get("organ_id"): row
        for row in contract_rows
        if isinstance(row, dict) and isinstance(row.get("organ_id"), str)
    }
    matrix_by_organ = {
        row.get("organ_id"): row
        for row in matrix_rows
        if isinstance(row, dict) and isinstance(row.get("organ_id"), str)
    }
    required_organs = set(DEPENDENCY_PREFLIGHT_REQUIRED_ORGANS)
    missing_contract_organs = sorted(required_organs - set(contract_by_organ))
    missing_matrix_organs = sorted(required_organs - set(matrix_by_organ))
    contract_required_fields = set(contract.get("required_receipt_fields", []))
    matrix_required_fields = set(matrix_contract.get("required_receipt_fields", []))
    missing_contract_receipt_fields = sorted(
        DEPENDENCY_PREFLIGHT_REQUIRED_RECEIPT_FIELDS - contract_required_fields
    )
    missing_matrix_receipt_fields = sorted(
        DEPENDENCY_PREFLIGHT_REQUIRED_RECEIPT_FIELDS - matrix_required_fields
    )
    code_gaps: dict[str, dict[str, list[str]]] = {}
    field_gaps: dict[str, dict[str, list[str]]] = {}
    command_shape_missing: list[str] = []
    anti_claim_missing: list[str] = []
    private_scan_missing: list[str] = []

    per_organ_required_fields = {"blocked_dependency_codes", "anti_claim", "private_state_scan"}
    for organ_id, expected_codes in DEPENDENCY_PREFLIGHT_REQUIRED_ORGANS.items():
        contract_row = contract_by_organ.get(organ_id, {})
        matrix_row = matrix_by_organ.get(organ_id, {})
        contract_codes = set(contract_row.get("blocked_dependency_error_codes", []) or [])
        matrix_codes = set(matrix_row.get("expected_error_codes", []) or [])
        missing_contract_codes = sorted(expected_codes - contract_codes)
        missing_matrix_codes = sorted(expected_codes - matrix_codes)
        if missing_contract_codes or missing_matrix_codes:
            code_gaps[organ_id] = {
                "missing_contract_codes": missing_contract_codes,
                "missing_matrix_codes": missing_matrix_codes,
            }

        contract_fields = set(contract_row.get("required_receipt_fields", []) or [])
        matrix_fields = set(matrix_row.get("receipt_fields_that_must_record_case", []) or [])
        missing_contract_fields = sorted(per_organ_required_fields - contract_fields)
        missing_matrix_fields = sorted(per_organ_required_fields - matrix_fields)
        if missing_contract_fields or missing_matrix_fields:
            field_gaps[organ_id] = {
                "missing_contract_fields": missing_contract_fields,
                "missing_matrix_fields": missing_matrix_fields,
            }

        if not contract_row.get("preflight_command_shape") or not matrix_row.get("preflight_command_shape"):
            command_shape_missing.append(organ_id)
        if not contract_row.get("anti_claim") or not matrix_row.get("anti_claim"):
            anti_claim_missing.append(organ_id)
        if not matrix_row.get("private_state_scan_focus"):
            private_scan_missing.append(organ_id)

    missing_plan_snippets = [
        snippet for snippet in DEPENDENCY_PREFLIGHT_PLAN_SNIPPETS if snippet not in validator_plan
    ]
    return {
        "contract_present": bool(contract),
        "matrix_contract_present": bool(matrix_contract),
        "required_organ_count": len(required_organs),
        "contract_organ_count": len(contract_by_organ),
        "matrix_organ_count": len(matrix_by_organ),
        "missing_contract_organs": missing_contract_organs,
        "missing_matrix_organs": missing_matrix_organs,
        "missing_contract_receipt_fields": missing_contract_receipt_fields,
        "missing_matrix_receipt_fields": missing_matrix_receipt_fields,
        "code_gaps": code_gaps,
        "field_gaps": field_gaps,
        "command_shape_missing": sorted(command_shape_missing),
        "anti_claim_missing": sorted(anti_claim_missing),
        "private_scan_missing": sorted(private_scan_missing),
        "missing_plan_snippets": missing_plan_snippets,
        "contract_anti_claim_present": bool(contract.get("anti_claim")),
        "matrix_anti_claim_present": bool(matrix_contract.get("anti_claim")),
        "contract_private_state_exclusions_count": len(contract.get("private_state_exclusions", []) or []),
    }


