def _typed_view_child_contracts_observed(
    canonical: dict[str, Any],
    overlay: dict[str, Any],
    pattern_order: dict[str, Any],
) -> dict[str, Any]:
    organ_id = "typed_view_contract_specimen"
    organ = next(
        (
            row for row in canonical.get("organs", []) or []
            if isinstance(row, dict) and row.get("organ_id") == organ_id
        ),
        {},
    )
    ratchet = canonical.get("organ_routing_cluster_coherence_ratchet_v1", {}) or {}
    refinement = next(
        (
            row for row in ratchet.get("child_contract_refinements", []) or []
            if isinstance(row, dict) and row.get("organ_id") == organ_id
        ),
        {},
    )
    contracts = [
        row for row in organ.get("child_contracts_v1", []) or []
        if isinstance(row, dict)
    ]
    contract_by_id = {
        row.get("child_contract_id"): row
        for row in contracts
        if isinstance(row.get("child_contract_id"), str)
    }
    contract_by_pattern: dict[str, str] = {}
    duplicate_contract_pattern_ids: list[str] = []
    contract_field_gaps: list[str] = []
    contract_policy_gaps: list[str] = []
    required_fields = {
        "child_contract_id",
        "role",
        "row_count",
        "pattern_ids",
        "route_reason",
        "fixture_contract",
        "validator_contract",
        "projection_policy",
        "anti_claim",
    }
    for contract in contracts:
        contract_id = str(contract.get("child_contract_id") or "")
        for field in required_fields:
            if contract.get(field) in (None, "", []):
                contract_field_gaps.append(f"{contract_id}:{field}")
        pattern_ids = [
            pattern_id for pattern_id in contract.get("pattern_ids", []) or []
            if isinstance(pattern_id, str)
        ]
        if contract.get("row_count") != len(pattern_ids):
            contract_field_gaps.append(f"{contract_id}:row_count_mismatch")
        if contract.get("role") != "child_contract_not_leaf":
            contract_policy_gaps.append(f"{contract_id}:role")
        projection_policy = str(contract.get("projection_policy", "")).lower()
        if "never direct leaf" not in projection_policy:
            contract_policy_gaps.append(f"{contract_id}:projection_policy")
        anti_claim = str(contract.get("anti_claim", "")).lower()
        if "does not" not in anti_claim and "not" not in anti_claim:
            contract_policy_gaps.append(f"{contract_id}:anti_claim")
        for pattern_id in pattern_ids:
            if pattern_id in contract_by_pattern:
                duplicate_contract_pattern_ids.append(pattern_id)
            contract_by_pattern[pattern_id] = contract_id

    overlay_rows = {
        row.get("pattern_id"): row
        for row in overlay.get("overlay_rows", []) or []
        if isinstance(row, dict) and isinstance(row.get("pattern_id"), str)
    }
    typed_overlay_ids = {
        pattern_id for pattern_id, row in overlay_rows.items()
        if row.get("corrected_organ_route") == organ_id
    }
    order_items = {
        item.get("item_id", "").split(":", 1)[1]: item
        for item in pattern_order.get("ordered_items", []) or []
        if isinstance(item, dict)
        and isinstance(item.get("item_id"), str)
        and item.get("item_id", "").startswith("pattern:")
    }
    typed_order_ids = {
        pattern_id for pattern_id, row in order_items.items()
        if row.get("primary_organ_id") == organ_id
    }
    organ_pattern_ids = {
        pattern_id
        for pattern_id in (
            list(organ.get("parent_pattern_ids", []) or [])
            + list(organ.get("fold_in_pattern_ids", []) or [])
        )
        if isinstance(pattern_id, str)
    }
    contract_pattern_ids = set(contract_by_pattern)

    overlay_binding_violations: list[str] = []
    overlay_direct_leaf_violations: list[str] = []
    order_binding_violations: list[str] = []
    allowed_overlay_roles = {
        "child_suborgan_not_candidate_leaf",
        "synthetic_or_schema_only_boundary_row",
    }
    allowed_order_route_classes = {
        "child_suborgan",
        "synthetic_only_private_organ",
    }
    for pattern_id in sorted(contract_pattern_ids):
        row = overlay_rows.get(pattern_id, {})
        contract_id = contract_by_pattern.get(pattern_id)
        if row.get("child_contract_id") != contract_id:
            overlay_binding_violations.append(f"{pattern_id}:child_contract_id")
        if row.get("corrected_role") not in allowed_overlay_roles:
            overlay_binding_violations.append(f"{pattern_id}:corrected_role")
        if row.get("corrected_organ_route") != organ_id:
            overlay_binding_violations.append(f"{pattern_id}:corrected_organ_route")
        if row.get("direct_leaf_allowed") is not False:
            overlay_direct_leaf_violations.append(pattern_id)
        if not row.get("route_reason"):
            overlay_binding_violations.append(f"{pattern_id}:route_reason")
        if "child_contracts_v1" not in str(row.get("route_reason_ref", "")):
            overlay_binding_violations.append(f"{pattern_id}:route_reason_ref")
        if contract_id not in str(row.get("fixture_validator_contract", "")):
            overlay_binding_violations.append(f"{pattern_id}:fixture_validator_contract")
        if "direct public leaf selection is forbidden" not in str(row.get("direct_leaf_guard_reason", "")):
            overlay_binding_violations.append(f"{pattern_id}:direct_leaf_guard_reason")
        if "typed_view_child_contract_bound" not in (row.get("normalization_flags", []) or []):
            overlay_binding_violations.append(f"{pattern_id}:normalization_flag")
        posture = str(row.get("public_projection_posture", ""))
        if "child_contract" not in posture or "never_direct_public_build_driver" not in posture:
            overlay_binding_violations.append(f"{pattern_id}:public_projection_posture")

        item = order_items.get(pattern_id, {})
        if item.get("route_class") not in allowed_order_route_classes:
            order_binding_violations.append(f"{pattern_id}:route_class")
        if item.get("child_contract_id") != contract_id:
            order_binding_violations.append(f"{pattern_id}:child_contract_id")
        if item.get("direct_leaf_allowed") is not False:
            order_binding_violations.append(f"{pattern_id}:direct_leaf_allowed")
        if item.get("projection_mode") != row.get("projection_mode"):
            order_binding_violations.append(f"{pattern_id}:projection_mode")
        order_posture = str(item.get("public_projection_posture", ""))
        if "child_contract" not in order_posture or "never_direct_public_build_driver" not in order_posture:
            order_binding_violations.append(f"{pattern_id}:public_projection_posture")

    summary = (overlay.get("summary") or {}).get("typed_view_child_contract_routing_v1", {}) or {}
    return {
        "organ_present": bool(organ),
        "organ_role": organ.get("role"),
        "organ_projection_posture": organ.get("public_projection_posture"),
        "validator_partition_required": "validate_typed_view_child_contract_partition"
        in (organ.get("validators_required", []) or []),
        "contract_count": len(contracts),
        "contract_ids": sorted(contract_by_id),
        "contract_row_count": len(contract_pattern_ids),
        "contract_declared_row_count_sum": sum(
            row.get("row_count", 0) for row in contracts if isinstance(row.get("row_count"), int)
        ),
        "contract_field_gaps": sorted(contract_field_gaps),
        "contract_policy_gaps": sorted(contract_policy_gaps),
        "duplicate_contract_pattern_ids": sorted(set(duplicate_contract_pattern_ids)),
        "organ_pattern_count": len(organ_pattern_ids),
        "overlay_route_count": len(typed_overlay_ids),
        "order_route_count": len(typed_order_ids),
        "contract_missing_organ_ids": sorted(organ_pattern_ids - contract_pattern_ids),
        "contract_extra_organ_ids": sorted(contract_pattern_ids - organ_pattern_ids),
        "contract_missing_overlay_ids": sorted(typed_overlay_ids - contract_pattern_ids),
        "contract_extra_overlay_ids": sorted(contract_pattern_ids - typed_overlay_ids),
        "contract_missing_order_ids": sorted(typed_order_ids - contract_pattern_ids),
        "contract_extra_order_ids": sorted(contract_pattern_ids - typed_order_ids),
        "overlay_binding_violations": sorted(overlay_binding_violations),
        "overlay_direct_leaf_violations": sorted(overlay_direct_leaf_violations),
        "order_binding_violations": sorted(order_binding_violations),
        "summary_status": summary.get("status"),
        "summary_child_contract_count": summary.get("child_contract_count"),
        "summary_row_count": summary.get("row_count"),
        "summary_route_reason_bound_count": summary.get("route_reason_bound_count"),
        "summary_direct_leaf_allowed_count": summary.get("direct_leaf_allowed_count"),
        "summary_contract_counts": summary.get("contract_counts", {}),
        "summary_synthetic_boundary_row_count": summary.get("synthetic_boundary_row_count"),
        "ratchet_refinement_status": refinement.get("status"),
        "ratchet_refinement_checker": refinement.get("checker_invariant"),
        "ratchet_refinement_row_count": refinement.get("row_count"),
        "ratchet_refinement_child_contract_count": refinement.get("child_contract_count"),
        "ratchet_refinement_contract_ids": sorted(refinement.get("contract_ids", []) or []),
        "ratchet_policy_forbids_direct_build_drivers": "none may become direct public build drivers"
        in str(refinement.get("build_driver_policy", "")),
    }


