def main() -> int:
    parser = argparse.ArgumentParser(description="Check macro-side microcosm projection readiness.")
    parser.add_argument("--write", action="store_true", help="write projection_readiness_check_receipt_v1.json")
    parser.add_argument("--pretty", action="store_true", help="print the full receipt")
    args = parser.parse_args()

    receipt = build_receipt()
    if args.write:
        RECEIPT.write_text(json.dumps(receipt, indent=2, sort_keys=False) + "\n", encoding="utf-8")
    if args.pretty:
        print(json.dumps(receipt, indent=2, sort_keys=False))
    else:
        print(json.dumps({
            "status": receipt["status"],
            "projection_ready": receipt["projection_ready"],
            "failed_invariants": receipt["failed_invariants"],
            "receipt": _rel(RECEIPT),
            "written": args.write,
        }, sort_keys=True))
    return 0 if receipt["status"] == "pass" else 1


if __name__ == "__main__":
    raise SystemExit(main())
